# 334. Increasing Triplet Subsequence
import math

class Solution:
    def increasingTriplet1(self, nums):
        # Edge Cases
        if len(nums) < 3:
            return False
        
        n = len(nums)

        for i in range(n-2):
            for j in range(i+1, n):
                for k in range(j+1, n):
                    if nums[i] < nums[j] < nums[k]:
                        # print(f"({nums[i]},{nums[j]},{nums[k]})")
                        return True

        return False            

    def increasingTriplet(self, nums):
        if len(nums) < 3:
            return False
        n = len(nums)

        first = math.inf
        second = math.inf
        for num in nums:
            if first < second < num:
                # print(i,j,index)
                return True
            
            if num <= first:
                first = num
                continue

            if num <= second:
                second = num
                continue
            
        return False


